import{_ as a,c as e,a2 as n,o as l}from"./chunks/framework.BQmytedh.js";const p="/assets/docker-mysql.CTOXx9Zp.webp",b=JSON.parse('{"title":"","description":"","frontmatter":{"sidebar":true,"lastUpdated":true},"headers":[],"relativePath":"install/docker-mysql-install.md","filePath":"install/docker-mysql-install.md","lastUpdated":1732848199000}'),t={name:"install/docker-mysql-install.md"};function i(o,s,c,d,r,h){return l(),e("div",null,s[0]||(s[0]=[n('<p><img src="'+p+`" alt="docker-mysql.png"></p><h2 id="一、下载" tabindex="-1">一、下载 <a class="header-anchor" href="#一、下载" aria-label="Permalink to &quot;一、下载&quot;">​</a></h2><p>下载镜像</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ docker pull mysql:8.0.16</span></span></code></pre></div><h2 id="二、配置文件" tabindex="-1">二、配置文件 <a class="header-anchor" href="#二、配置文件" aria-label="Permalink to &quot;二、配置文件&quot;">​</a></h2><p>将全部的配置文件和关联的文件夹统一放到<code>/opt/docker-mysql</code>中</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ mkdir -p /opt/docker-mysql/conf.d</span></span></code></pre></div><p>增加并修改配置文件<code>config-file.cnf</code></p><p>内容如下,设置表名不区分大小写; linux下默认是区分的，windows下默认不区分</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[mysqld]</span></span>
<span class="line"><span># 表名不区分大小写</span></span>
<span class="line"><span>lower_case_table_names=1 </span></span>
<span class="line"><span>#server-id=1</span></span>
<span class="line"><span>datadir=/var/lib/mysql</span></span>
<span class="line"><span>#socket=/var/lib/mysql/mysqlx.sock</span></span>
<span class="line"><span>#symbolic-links=0</span></span>
<span class="line"><span># sql_mode=NO_ENGINE_SUBSTITUTION,STRICT_TRANS_TABLES </span></span>
<span class="line"><span>[mysqld_safe]</span></span>
<span class="line"><span>log-error=/var/log/mysqld.log</span></span>
<span class="line"><span>pid-file=/var/run/mysqld/mysqld.pid</span></span></code></pre></div><h2 id="三、启动" tabindex="-1">三、启动 <a class="header-anchor" href="#三、启动" aria-label="Permalink to &quot;三、启动&quot;">​</a></h2><p>增加数据文件夹</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ mkdir -p /opt/docker-mysql/var/lib/mysql</span></span></code></pre></div><p>启动，设置默认密码 <code>123456-abc</code>，TZ 设置容器的默认时区</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ docker run --name mysql \\</span></span>
<span class="line"><span>	--restart=always \\</span></span>
<span class="line"><span>	-p 3306:3306 \\</span></span>
<span class="line"><span>	-v /opt/docker-mysql/conf.d:/etc/mysql/conf.d \\</span></span>
<span class="line"><span>	-v /opt/docker-mysql/var/lib/mysql:/var/lib/mysql \\</span></span>
<span class="line"><span>	-e MYSQL_ROOT_PASSWORD=123456-abc \\</span></span>
<span class="line"><span>	-e TZ=Asia/Shanghai \\</span></span>
<span class="line"><span>	-d mysql:8.0.16</span></span></code></pre></div><h2 id="四、-常用命令" tabindex="-1">四、 常用命令 <a class="header-anchor" href="#四、-常用命令" aria-label="Permalink to &quot;四、 常用命令&quot;">​</a></h2><p>进入容器</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ docker exec -it mysql bash</span></span></code></pre></div><p>查看日志</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ docker logs -f mysql</span></span></code></pre></div><p>备份数据</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ docker exec mysql sh -c &#39;exec mysqldump --all-databases -uroot -p&quot;123456-abc&quot;&#39; &gt; /some/path/on/your/host/all-databases.sql</span></span></code></pre></div><p>恢复数据</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ docker exec -i mysql sh -c &#39;exec mysql -uroot -p&quot;123456-abc&quot;&#39; &lt; /some/path/on/your/host/all-databases.sql</span></span></code></pre></div><h2 id="五、-其他问题" tabindex="-1">五、 其他问题 <a class="header-anchor" href="#五、-其他问题" aria-label="Permalink to &quot;五、 其他问题&quot;">​</a></h2><h4 id="only-full-group-by-问题" tabindex="-1">only_full_group_by 问题 <a class="header-anchor" href="#only-full-group-by-问题" aria-label="Permalink to &quot;only_full_group_by 问题&quot;">​</a></h4><p>如果安装的版本是 <code>5.7</code>版本, 查询数据时出现如下错误</p><blockquote><p>this is incompatible with sql_mode=only_full_group_by</p></blockquote><p>可以使用使用下列方式解决</p><h5 id="_1-查询-sql-mode" tabindex="-1">1. 查询 <code>sql_mode</code> <a class="header-anchor" href="#_1-查询-sql-mode" aria-label="Permalink to &quot;1. 查询 \`sql_mode\`&quot;">​</a></h5><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>select @@sql_mode</span></span></code></pre></div><p>结果如下</p><blockquote><p>ONLY_FULL_GROUP_BY,STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION</p></blockquote><h5 id="_2-重置" tabindex="-1">2. 重置 <a class="header-anchor" href="#_2-重置" aria-label="Permalink to &quot;2. 重置&quot;">​</a></h5><p>删除其中的 <code>ONLY_FULL_GROUP_BY</code>配置，重新设置到 <code>config-file.cnf</code>中</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[mysqld]</span></span>
<span class="line"><span># 表名不区分大小写</span></span>
<span class="line"><span>lower_case_table_names=1 </span></span>
<span class="line"><span>#server-id=1</span></span>
<span class="line"><span>datadir=/var/lib/mysql</span></span>
<span class="line"><span>#socket=/var/lib/mysql/mysqlx.sock</span></span>
<span class="line"><span>#symbolic-links=0</span></span>
<span class="line"><span>sql_mode=STRICT_TRANS_TABLES,NO_ZERO_IN_DATE,NO_ZERO_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION</span></span>
<span class="line"><span>[mysqld_safe]</span></span>
<span class="line"><span>log-error=/var/log/mysqld.log</span></span>
<span class="line"><span>pid-file=/var/run/mysqld/mysqld.pid</span></span></code></pre></div><h5 id="_3-重启容器" tabindex="-1">3. 重启容器 <a class="header-anchor" href="#_3-重启容器" aria-label="Permalink to &quot;3. 重启容器&quot;">​</a></h5><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ docker restart mysql</span></span></code></pre></div>`,38)]))}const m=a(t,[["render",i]]);export{b as __pageData,m as default};
